/// Highlight code content with syntax tokens.
pub fn highlight_code(content: &str, lang: &str) -> Vec<Vec<SyntaxToken>> {
    let language = Language::from_fence(lang);
    content
        .lines()
        .map(|line| tokenize_line(line, language))
        .collect()
}

