pub(crate) fn delete_before_cursor(&mut self) {
    if self.cursor_pos > 0 {
        self.push_undo();
        let new_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
        self.input.drain(new_pos..self.cursor_pos);
        self.cursor_pos = new_pos;
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    } else if self.cursor_pos == 0 && !self.input.is_empty() {
        // Cursor at start of line - check if there's a newline to remove
        if let Some(newline_pos) = self.input.find('\n') {
            self.push_undo();
            // Remove the newline character (join with previous line)
            self.input.remove(newline_pos);
            // Cursor stays at 0 (now pointing at what was after the newline)
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    } else {
        self.input_flash = 3;
    }
}

