/// Run a bash command and display output
fn run_bash_command(&mut self, command: &str) {
    use std::process::{Command, Stdio};

    let output = Command::new("sh")
        .arg("-c")
        .arg(command)
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .output();

    let (stdout, stderr, exit_code) = match output {
        Ok(out) => (
            String::from_utf8_lossy(&out.stdout).to_string(),
            String::from_utf8_lossy(&out.stderr).to_string(),
            out.status.code().unwrap_or(-1),
        ),
        Err(e) => {
            self.add_system_msg(format!("Error running command: {}", e));
            return;
        }
    };

    let mut result = String::new();
    if !stdout.is_empty() {
        result.push_str(&stdout);
    }
    if !stderr.is_empty() {
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str("stderr: ");
        result.push_str(&stderr);
    }
    if result.is_empty() {
        result = format!("(exit code: {})", exit_code);
    }

    // Add the command and output as a system message
    let output_msg = format!("$ {}\n{}", command, result);
    self.add_system_msg(output_msg);
    self.scroll = 0;
    self.messages_changed();
}

